def transform(table):
    if not table:
        return []
    header = table[0]
    data = table[1:]
    if not data:
        return []
    first_row = data[0]
    if len(first_row) != len(header):
        return []
    product_col_idx = header.index("Product")
    price_col_idx = header.index("Price")
    if product_col_idx == -1 or price_col_idx == -1:
        return []
    product_map = {}
    for row in data:
        if len(row) != len(header):
            continue
        product = row[product_col_idx]
        if product not in product_map:
            product_map[product] = []
        product_map[product].append(row)
    result = []
    for product, rows in product_map.items():
        new_row = [header[0], header[1], rows[0][product_col_idx], rows[0][price_col_idx]]
        for row in rows[1:]:
            new_row.append(row[product_col_idx])
            new_row.append(row[price_col_idx])
        result.append(new_row)
    return result

